import{c as s,Q as a,j as t,m as i}from"./chunks/framework.DVkeSyfh.js";const k=JSON.parse('{"title":"Скрипт оптимизации базы данных","description":"","frontmatter":{},"headers":[],"relativePath":"ru/scripts/optimize-database.md","filePath":"ru/scripts/optimize-database.md","lastUpdated":1780017229000}'),p={name:"ru/scripts/optimize-database.md"};function n(l,e,o,d,c,r){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="скрипт-оптимизации-базы-данных" tabindex="-1">Скрипт оптимизации базы данных <a class="header-anchor" href="#скрипт-оптимизации-базы-данных" aria-label="Permalink to &quot;Скрипт оптимизации базы данных&quot;">​</a></h1><p>По возможности запускайте этот скрипт в проектном окружении Python:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\optimize_database.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">help</span></span></code></pre></div><p>Оптимизирует базу данных SQLite, которая уже соответствует текущему контракту схемы. Скрипт проверяет схему, создаёт резервную копию, выполняет <code>VACUUM</code>, <code>ANALYZE</code> и проверяет целостность. Он не мигрирует, не восстанавливает и не адаптирует базы данных со старыми схемами.</p><p>Используйте этот скрипт после крупного сканирования, сброса, очистки, переноса или интенсивного анализа, если файл SQLite вырос или вам нужна свежая проверка целостности. Он не входит в обычное повседневное использование и не должен применяться для устранения проблем с версией схемы.</p><p>Использование:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python scripts\\optimize_database.py --db DB</span></span></code></pre></div><p>Пример:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\optimize_database.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite</span></span></code></pre></div><p>Этот скрипт пишет в базу данных и создаёт резервную копию рядом с ней. Если схема базы данных неактуальна, скрипт выводит ошибку и останавливается до создания резервной копии или изменения базы данных.</p><p>Существует только один режим работы и нет dry-run: каждый успешный запуск проверяет схему, создаёт резервную копию и оптимизирует файл на месте.</p><h2 id="как-это-работает" tabindex="-1">Как это работает <a class="header-anchor" href="#как-это-работает" aria-label="Permalink to &quot;Как это работает&quot;">​</a></h2><ol><li>Требует, чтобы файл <code>--db</code> существовал.</li><li>Выполняет <code>PRAGMA integrity_check</code>; прерывается, если результат не <code>ok</code>.</li><li>Проверяет текущий контракт схемы (<code>user_version = 2</code>, ожидаемые таблицы <code>embeddings</code>, <code>library_settings</code>, <code>track_classifier_scores</code>, <code>track_likes</code> и <code>tracks</code>, а также их столбцы, индексы, триггеры и внешние ключи). Любое несоответствие прерывает работу до создания резервной копии.</li><li>Создаёт онлайн-резервную копию SQLite с именем <code>&lt;db-name&gt;.bak-&lt;YYYYMMDD-HHMMSS&gt;</code> рядом с базой данных (если такое имя уже существует, добавляется числовой суффикс).</li><li>Включает журналирование WAL, затем выполняет <code>VACUUM</code>, <code>ANALYZE</code>, <code>PRAGMA optimize</code> и усекающую контрольную точку WAL.</li><li>Снова выполняет <code>PRAGMA integrity_check</code>; прерывается, если результат не <code>ok</code>.</li></ol><h2 id="вывод" tabindex="-1">Вывод <a class="header-anchor" href="#вывод" aria-label="Permalink to &quot;Вывод&quot;">​</a></h2><p>В случае успеха скрипт выводит короткую сводку в стандартный вывод:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>database=&lt;resolved database path&gt;</span></span>
<span class="line"><span>backup=&lt;backup file path&gt;</span></span>
<span class="line"><span>integrity_before=ok</span></span>
<span class="line"><span>integrity_after=ok</span></span>
<span class="line"><span>size_before=&lt;bytes&gt;</span></span>
<span class="line"><span>size_after=&lt;bytes&gt;</span></span>
<span class="line"><span>user_version=2</span></span></code></pre></div><p>Единственный файл, который скрипт пишет помимо оптимизированной базы данных, — это резервная копия <code>&lt;db-name&gt;.bak-&lt;timestamp&gt;</code>. Никаких отчётов в формате JSON, XLSX или лога нет.</p><blockquote><p>Внимание: этот скрипт предназначен только для баз данных с актуальной схемой. Он отказывается работать со старыми или неожиданными схемами вместо их миграции и не запрашивает подтверждения перед оптимизацией.</p></blockquote><p>Закройте работающее приложение перед оптимизацией той же базы данных, чтобы резервное копирование, <code>VACUUM</code> и проверка целостности выполнялись на спокойном файле.</p>`,19)])])}const b=s(p,[["render",n]]);export{k as __pageData,b as default};
